class Solution {
    public int maximumProductOfWordLengths(String[] data) {
        int maxProduct = 0;
        int n = data.length;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (!shareCommonLetters(data[i], data[j])) {
                    int product = data[i].length() * data[j].length();
                    maxProduct = Math.max(maxProduct, product);
                }
            }
        }
        return maxProduct;
    }
    private boolean shareCommonLetters(String word1, String word2) {
        boolean[] letters = new boolean[26];
        for (char c : word1.toCharArray()) {
            letters[c - 'a'] = true;
        }
        for (char c : word2.toCharArray()) {
            if (letters[c - 'a']) {
                return true;
            }
        }
        return false;
    }
}

