func maximumProductOfWordLengths(data []string) int {
    maxProduct := 0
    n := len(data)

    for i := 0; i < n; i++ {
        for j := i + 1; j < n; j++ {
            if noCommonLetters(data[i], data[j]) {
                product := len(data[i]) * len(data[j])
                if product > maxProduct {
                    maxProduct = product
                }
            }
        }
    }
    return maxProduct
}

func noCommonLetters(word1, word2 string) bool {
    charSet := make(map[rune]struct{})

    for _, char := range word1 {
        charSet[char] = struct{}{}
    }

    for _, char := range word2 {
        if _, exists := charSet[char]; exists {
            return false
        }
    }

    return true
}

