class Solution {
    public int maximumProductOfWordLengths(String[] data) {
        int n = data.length;
        int[] masks = new int[n];
        int[] lengths = new int[n];
        for (int i = 0; i < n; i++) {
            for (char c : data[i].toCharArray()) {
                masks[i] |= 1 << (c - 'a');
            }
            lengths[i] = data[i].length();
        }
        int maxProduct = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if ((masks[i] & masks[j]) == 0) {
                    maxProduct = Math.max(maxProduct, lengths[i] * lengths[j]);
                }
            }
        }
        return maxProduct;
    }
}

