func maximumProductOfWordLengths(data []string) int {
    n := len(data)
    masks := make([]int, n)
    lengths := make([]int, n)

    for i, word := range data {
        for _, ch := range word {
            masks[i] |= 1 << (ch - 'a')
        }
        lengths[i] = len(word)
    }

    maxProduct := 0
    for i := 0; i < n; i++ {
        for j := i + 1; j < n; j++ {
            if masks[i]&masks[j] == 0 {
                product := lengths[i] * lengths[j]
                if product > maxProduct {
                    maxProduct = product
                }
            }
        }
    }

    return maxProduct
}

