public class Solution {
    public int maximumProductOfWordLengths(String[] data) {
        int n = data.Length;
        int[] bitMasks = new int[n];
        int[] lengths = new int[n];

        for (int i = 0; i < n; i++) {
            lengths[i] = data[i].Length;
            foreach (char c in data[i]) {
                bitMasks[i] |= 1 << (c - 'a');
            }
        }

        int maxProduct = 0;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if ((bitMasks[i] & bitMasks[j]) == 0) {
                    maxProduct = Math.Max(maxProduct, lengths[i] * lengths[j]);
                }
            }
        }

        return maxProduct;
    }
}
